const items = $input.all();
const project = $('プロジェクトループ').item.json;
const today = new Date().toISOString().split('T')[0];

const escapeSql = s => String(s).replace(/'/g, "''");

const rows = items.map(item => {
  const row = item.json;
  const progress = parseFloat(String(row['進捗'] || '0').replace('%', '').trim()) || 0;
  const deadline = row['期限'] ? String(row['期限']).trim() || null : null;
  return {
    project_id: project.id,
    phase: escapeSql(String(row['フェーズ'] || '')),
    task: escapeSql(String(row['タスク'] || '')),
    status: escapeSql(String(row['ステータス'] || '')),
    progress: Math.min(100, Math.max(0, progress)),
    deadline: deadline,
    resister_day: today
  };
}).filter(r => r.task !== '');

let bulkInsertSql = 'SELECT 1';
if (rows.length > 0) {
  const valueRows = rows.map(r => {
    const deadlineVal = r.deadline ? "'" + r.deadline + "'" : 'NULL';
    return '(' + r.project_id + ", '" + r.phase + "', '" + r.task + "', '" + r.status + "', " + r.progress + ', ' + deadlineVal + ", '" + r.resister_day + "')";
  }).join(',\n');
  bulkInsertSql = 'INSERT INTO project_progress (project_id, phase, task, status, progress, deadline, resister_day) VALUES\n' + valueRows;
}

return [{
  json: {
    project_id: project.id,
    today: today,
    row_count: rows.length,
    bulk_insert_sql: bulkInsertSql
  }
}];

const items = $input.all();
const project = $('プロジェクトループ').item.json;
const today = new Date().toISOString().split('T')[0];
const now = new Date();

// resister_day ごとにグループ化
const byDay = {};
for (const item of items) {
  const raw = item.json.resister_day;
  const day = raw instanceof Date ? raw.toISOString().split('T')[0] : String(raw).split('T')[0];
  if (!byDay[day]) byDay[day] = [];
  byDay[day].push(item.json);
}

const sortedDays = Object.keys(byDay).sort();
const latestDay = sortedDays[sortedDays.length - 1];
const todayData = byDay[latestDay] || [];

// 全体進捗率
const overallProgress = todayData.length > 0
  ? todayData.reduce((sum, t) => sum + (parseFloat(t.progress) || 0), 0) / todayData.length
  : 0;

// フェーズ別サマリー
const phaseMap = {};
for (const task of todayData) {
  const ph = task.phase || 'unknown';
  if (!phaseMap[ph]) phaseMap[ph] = [];
  phaseMap[ph].push(task);
}
const phaseSummary = {};
for (const ph in phaseMap) {
  const pts = phaseMap[ph];
  phaseSummary[ph] = {
    progress: pts.reduce((s, t) => s + (parseFloat(t.progress) || 0), 0) / pts.length,
    task_count: pts.length,
    status_dist: pts.reduce((acc, t) => { acc[t.status] = (acc[t.status] || 0) + 1; return acc; }, {})
  };
}

// リスク検知
const risks = [];

const overdueTasks = todayData.filter(t => t.deadline && new Date(t.deadline) < now && t.status !== '完了');
if (overdueTasks.length > 0) {
  risks.push({
    type: 'overdue',
    severity: 'high',
    count: overdueTasks.length,
    tasks: overdueTasks.map(t => ({ task: t.task, phase: t.phase, deadline: t.deadline }))
  });
}

if (project.start_date && project.end_date) {
  const totalDays = (new Date(project.end_date) - new Date(project.start_date)) / 86400000;
  const elapsedDays = (now - new Date(project.start_date)) / 86400000;
  const timeProgress = Math.min((elapsedDays / totalDays) * 100, 100);
  if (timeProgress - overallProgress > 20) {
    risks.push({
      type: 'delayed',
      severity: 'high',
      time_progress: Math.round(timeProgress),
      actual_progress: Math.round(overallProgress)
    });
  }
}

if (sortedDays.length >= 2) {
  const firstDayData = byDay[sortedDays[0]];
  const stagnant = todayData.filter(t => {
    if (t.status === '完了') return false;
    const first = firstDayData.find(f => f.task === t.task && f.phase === t.phase);
    return first && parseFloat(first.progress) === parseFloat(t.progress);
  });
  if (stagnant.length > 0) {
    risks.push({
      type: 'stagnant',
      severity: 'medium',
      count: stagnant.length,
      tasks: stagnant.map(t => ({ task: t.task, phase: t.phase, progress: t.progress }))
    });
  }
}

// トレンド・完了予測
const dailyProgress = sortedDays.map(day => ({
  date: day,
  progress: byDay[day].reduce((s, t) => s + (parseFloat(t.progress) || 0), 0) / byDay[day].length
}));

let completionEstimate = null;
if (dailyProgress.length >= 2) {
  const first = dailyProgress[0];
  const last = dailyProgress[dailyProgress.length - 1];
  const daysDiff = (new Date(last.date) - new Date(first.date)) / 86400000;
  const dailyRate = daysDiff > 0 ? (last.progress - first.progress) / daysDiff : 0;
  if (dailyRate > 0) {
    const daysLeft = (100 - last.progress) / dailyRate;
    completionEstimate = new Date(Date.now() + daysLeft * 86400000).toISOString().split('T')[0];
  }
}

const escapeSql = s => String(s).replace(/'/g, "''");

return [{
  json: {
    project_id: project.id,
    report_date: today,
    overall_progress: Math.round(overallProgress * 100) / 100,
    phase_summary_sql: escapeSql(JSON.stringify(phaseSummary)),
    risks_sql: escapeSql(JSON.stringify(risks)),
    trend_sql: escapeSql(JSON.stringify({ daily_progress: dailyProgress, completion_estimate: completionEstimate }))
  }
}];

const analysisData = $('進捗分析').item.json;
const project = $('プロジェクトループ').item.json;
const risks = JSON.parse(analysisData.risks_sql);
const phaseSummary = JSON.parse(analysisData.phase_summary_sql);
const trend = JSON.parse(analysisData.trend_sql);
const phaseLines = Object.entries(phaseSummary).map(([ph, d]) => '  - ' + ph + ': 進捗 ' + Math.round(d.progress) + '%、タスク数 ' + d.task_count).join('\n');
const riskLines = risks.map(r => {
  if (r.type === 'overdue') return '  - 期限超過（高）: ' + r.count + '件';
  if (r.type === 'delayed') return '  - 進捗遅延（高）: 時間消化' + r.time_progress + '%に対し進捗' + r.actual_progress + '%';
  if (r.type === 'stagnant') return '  - 進捗停滞（中）: ' + r.count + '件';
  return '';
}).filter(Boolean).join('\n');
const completion = trend.completion_estimate || '未算出';
const lines = [
  'あなたはPMO（プロジェクトマネジメントオフィス）担当者です。以下の日次レポートを分析し、次のアクション判断のための実務的コメントを日本語200〜400字で記述してください。',
  '',
  '【プロジェクト情報】',
  '- プロジェクト名: ' + project.name,
  '- レポート日: ' + analysisData.report_date,
  '- 全体進捗率: ' + analysisData.overall_progress + '%',
  '- 完了予測日: ' + completion,
  '',
  '【フェーズ別進捗】',
  phaseLines || '  データなし',
  '',
  '【検知リスク】',
  riskLines || '  リスクなし',
  '',
  '優先対処すべきリスクとその根拠、推奨アクションを簡潔に記述してください。'
];
return [{json: {project_id: analysisData.project_id, report_date: analysisData.report_date, prompt: lines.join('\n')}}];

const aiOutput = $json.output;
const meta = $('PMOコメントプロンプト生成').item.json;
const escapeSql = s => String(s).replace(/'/g, "''");
const comment = escapeSql(aiOutput.trim());
const q = "'";
return [{json: {update_sql: 'UPDATE daily_reports SET ai_comment = ' + q + comment + q + ' WHERE project_id = ' + meta.project_id + ' AND report_date = ' + q + meta.report_date + q}}];
